/* ── Reset ── */
*, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }
body { font-family: 'Pretendard', 'Malgun Gothic', sans-serif; background: #f8fafc; color: #1e293b; overflow-x: hidden; -webkit-font-smoothing: antialiased; }

/* ── Header ── */
.top-header { background: #07111f; position: sticky; top: 0; z-index: 1000; border-bottom: 1px solid rgba(255,255,255,0.06); }
.header-inner { max-width: 1280px; margin: 0 auto; height: 56px; display: flex; align-items: center; justify-content: space-between; padding: 0 24px; gap: 16px; }

.logo { display: flex; align-items: center; gap: 10px; cursor: pointer; flex-shrink: 0; }
.logo-mark { width: 28px; height: 28px; border-radius: 7px; background: #1d4ed8; display: grid; grid-template-columns: 1fr 1fr; grid-template-rows: 1fr 1fr; gap: 3px; padding: 5px; }
.logo-mark div { background: white; border-radius: 1px; }
.logo-mark div:last-child { background: #60a5fa; }
.logo-name { font-size: 17px; font-weight: 800; color: white; letter-spacing: -0.5px; }
.logo-name em { color: #60a5fa; font-style: normal; }

.grade-nav { display: flex; gap: 2px; flex: 1; justify-content: center; }
.gtab { font-size: 13px; color: rgba(255,255,255,0.38); font-weight: 600; padding: 5px 12px; border-radius: 6px; cursor: pointer; border: none; background: transparent; transition: 0.15s; font-family: inherit; }
.gtab:hover { color: rgba(255,255,255,0.7); }
.gtab.active { color: white; background: rgba(255,255,255,0.1); }

.header-right { flex-shrink: 0; }
.mixer-btn { display: flex; align-items: center; gap: 8px; background: #1d4ed8; color: white; border: none; border-radius: 8px; padding: 8px 16px; font-size: 13px; font-weight: 700; font-family: inherit; cursor: pointer; transition: background 0.15s; }
.mixer-btn:hover { background: #1e40af; }
.mixer-btn-icon { width: 14px; height: 14px; display: grid; grid-template-columns: 1fr 1fr; gap: 2px; flex-shrink: 0; }
.mixer-btn-icon::before, .mixer-btn-icon::after { content: ''; background: rgba(255,255,255,0.7); border-radius: 1px; }
.cart-badge { background: white; color: #1d4ed8; font-size: 11px; font-weight: 800; border-radius: 999px; padding: 1px 7px; min-width: 20px; text-align: center; }

/* ── Panel ── */
.app-panel { display: none; }
.app-panel.active { display: block; }

/* ── Hero ── */
.hero { background: #f0f4ff; border-bottom: 1px solid #dbeafe; padding: 36px 24px 48px; position: relative; overflow: hidden; }
.hero-grid-bg { position: absolute; inset: 0; opacity: 0.3; background-image: linear-gradient(#c7d7fe 1px, transparent 1px), linear-gradient(90deg, #c7d7fe 1px, transparent 1px); background-size: 32px 32px; }
.hero-deco { position: absolute; right: 8%; top: 20px; opacity: 0.12; pointer-events: none; font-size: 20px; color: #1d4ed8; line-height: 2.4; text-align: right; font-family: 'Nanum Myeongjo', serif; }
.hero-inner { max-width: 1280px; margin: 0 auto; display: flex; align-items: flex-end; justify-content: space-between; gap: 24px; position: relative; }

.hero-eyebrow { display: inline-flex; align-items: center; gap: 7px; background: #dbeafe; border: 1px solid #bfdbfe; border-radius: 999px; padding: 4px 14px; margin-bottom: 16px; }
.eyebrow-dot { width: 6px; height: 6px; border-radius: 50%; background: #2563eb; flex-shrink: 0; }
.hero-eyebrow span:last-child { font-size: 11px; font-weight: 700; color: #1d4ed8; letter-spacing: 0.6px; text-transform: uppercase; }
.hero-title { font-size: clamp(22px, 4vw, 30px); font-weight: 800; color: #0f172a; line-height: 1.25; letter-spacing: -0.8px; margin-bottom: 10px; word-break: keep-all; }
.hero-title em { color: #1d4ed8; font-style: normal; }
.hero-desc { font-size: 13px; color: #64748b; line-height: 1.7; }

.stat-pills { display: flex; gap: 12px; flex-shrink: 0; }
.stat-pill { background: #fff; border: 1px solid #dbeafe; border-radius: 12px; padding: 16px 20px; text-align: center; min-width: 90px; }
.stat-n { font-size: 26px; font-weight: 800; color: #1d4ed8; line-height: 1; font-variant-numeric: tabular-nums; }
.stat-l { font-size: 11px; color: #64748b; font-weight: 600; margin-top: 5px; white-space: nowrap; }

/* ── Filter Band ── */
.filter-band { background: white; border-bottom: 1px solid #e2e8f0; position: sticky; top: 56px; z-index: 900; }
.filter-inner { max-width: 1280px; margin: 0 auto; padding: 10px 24px; display: flex; align-items: center; gap: 10px; flex-wrap: wrap; }
.fb-search { flex: 1; min-width: 180px; position: relative; }
.fb-search-icon { position: absolute; left: 12px; top: 50%; transform: translateY(-50%); font-size: 13px; color: #94a3b8; pointer-events: none; }
.fb-search input { width: 100%; background: #f8fafc; border: 1px solid #e2e8f0; border-radius: 8px; padding: 9px 14px 9px 36px; font-size: 13px; color: #1e293b; font-family: inherit; outline: none; transition: border-color 0.15s; }
.fb-search input:focus { border-color: #1d4ed8; background: white; }
.fb-divider { width: 1px; height: 24px; background: #e2e8f0; flex-shrink: 0; }
.fb-sel-group { display: flex; gap: 6px; flex-wrap: wrap; }
.fb-sel { background: #f8fafc; border: 1px solid #e2e8f0; border-radius: 8px; padding: 8px 12px; font-size: 13px; color: #1e293b; font-family: inherit; cursor: pointer; font-weight: 600; outline: none; }
.fb-sel:focus { border-color: #1d4ed8; }
.fb-reset { padding: 8px 14px; border: 1px solid #e2e8f0; border-radius: 8px; background: white; font-size: 13px; font-weight: 600; color: #64748b; font-family: inherit; cursor: pointer; transition: 0.15s; }
.fb-reset:hover { border-color: #94a3b8; color: #334155; }
.count-label { font-size: 13px; font-weight: 600; color: #94a3b8; white-space: nowrap; margin-left: auto; }

/* ── Content & Grid ── */
.content-wrap { max-width: 1280px; margin: 0 auto; padding: 24px; }
.card-grid { display: grid; grid-template-columns: repeat(auto-fill, minmax(240px, 1fr)); gap: 12px; }

/* ── Card ── */
.exam-card { background: white; border: 1px solid #f1f5f9; border-radius: 14px; overflow: hidden; display: flex; flex-direction: column; transition: transform 0.18s ease, box-shadow 0.18s ease, border-color 0.18s ease; }
.exam-card:hover { transform: translateY(-3px); box-shadow: 0 10px 28px rgba(15,23,42,0.09); border-color: #dbeafe; }

.card-top { height: 4px; background: #1d4ed8; flex-shrink: 0; }
.card-body { padding: 16px; flex: 1; }
.card-grade-label { font-size: 11px; font-weight: 700; color: #64748b; margin-bottom: 6px; }
.card-school { font-size: 16px; font-weight: 800; color: #0f172a; margin-bottom: 4px; line-height: 1.35; }
.card-sub { font-size: 12px; color: #64748b; margin-bottom: 10px; }
.card-chips { display: flex; flex-wrap: wrap; gap: 5px; }
.chip { font-size: 11px; font-weight: 600; color: #475569; background: #f1f5f9; padding: 2px 8px; border-radius: 5px; }
.chip.blue { color: #1d4ed8; background: #dbeafe; }
.chip.green { color: #059669; background: #d1fae5; }

.card-actions { display: flex; border-top: 1px solid #f1f5f9; }
.action-btn { flex: 1; padding: 10px 4px; font-size: 12px; font-weight: 700; color: #64748b; background: white; border: none; border-right: 1px solid #f1f5f9; cursor: pointer; font-family: inherit; transition: 0.15s; text-align: center; }
.action-btn:last-child { border-right: none; }
.action-btn:hover { background: #f8fafc; color: #1d4ed8; }
.action-btn.cart-btn { color: #1d4ed8; }
.action-btn.cart-btn.in-cart { color: #b91c1c; background: #fef2f2; }

/* ── Status boxes ── */
.status-box { padding: 60px 0; text-align: center; font-weight: 600; font-size: 15px; border-radius: 12px; grid-column: 1 / -1; }
.status-box.loading { color: #1d4ed8; background: #eff6ff; border: 1px solid #dbeafe; }
.status-box.error { color: #dc2626; background: #fef2f2; border: 1px solid #fee2e2; }
.status-box.empty { color: #94a3b8; background: white; border: 1px dashed #cbd5e1; }

/* ── Mixer ── */
.mixer-header { display: flex; justify-content: space-between; align-items: center; padding: 20px 24px; border-bottom: 1px solid #e2e8f0; background: white; }
.mixer-info { display: flex; align-items: center; gap: 14px; }
.mixer-info h3 { font-size: 17px; color: #0f172a; }
.back-btn { background: none; border: none; font-size: 13px; font-weight: 600; color: #64748b; cursor: pointer; font-family: inherit; padding: 6px 12px; border-radius: 7px; transition: 0.15s; }
.back-btn:hover { background: #f1f5f9; color: #1e293b; }

.mixer-settings { display: grid; grid-template-columns: repeat(auto-fit, minmax(240px, 1fr)); gap: 16px; padding: 20px 24px; background: white; border-bottom: 1px solid #e2e8f0; }
.setting-item { display: flex; flex-direction: column; gap: 7px; }
.setting-item label { font-size: 12px; font-weight: 700; color: #64748b; text-transform: uppercase; letter-spacing: 0.4px; }
.setting-item input, .setting-item select { padding: 9px 13px; border: 1px solid #cbd5e1; border-radius: 8px; background: white; font: inherit; font-size: 14px; color: #1e293b; }
.info-msg { grid-column: 1 / -1; color: #94a3b8; font-size: 13px; }

.list-container { background: white; padding: 0 24px; min-height: 80px; }
.mixer-item { display: flex; justify-content: space-between; align-items: center; gap: 16px; padding: 14px 0; border-bottom: 1px solid #f1f5f9; }
.mixer-item:last-child { border-bottom: none; }
.item-desc { display: flex; flex-direction: column; gap: 4px; min-width: 0; }
.item-main { font-weight: 700; font-size: 15px; color: #0f172a; display: flex; align-items: center; gap: 8px; }
.item-grade { font-size: 12px; font-weight: 600; color: #64748b; background: #f1f5f9; padding: 2px 7px; border-radius: 5px; }
.item-sub { font-size: 13px; color: #64748b; font-weight: 500; }
.btn-remove { background: none; border: none; color: #cbd5e1; cursor: pointer; font-size: 16px; padding: 5px 8px; border-radius: 6px; transition: 0.15s; flex-shrink: 0; }
.btn-remove:hover { color: #ef4444; background: #fef2f2; }

.mixer-actions { padding: 20px 24px; display: flex; gap: 10px; background: white; border-top: 1px solid #e2e8f0; }

/* ── Buttons ── */
.btn-primary, .btn-secondary, .btn-ghost { cursor: pointer; font-weight: 700; border-radius: 8px; font-size: 14px; font-family: inherit; transition: all 0.15s; padding: 11px 18px; }
.btn-primary { background: #1d4ed8; color: white; border: 1px solid #1d4ed8; flex: 2; }
.btn-primary:hover { background: #1e40af; }
.btn-primary:disabled { background: #94a3b8; border-color: #94a3b8; cursor: not-allowed; }
.btn-secondary { background: white; color: #334155; border: 1px solid #cbd5e1; flex: 1; }
.btn-secondary:hover { background: #f8fafc; border-color: #94a3b8; }
.btn-secondary:disabled { color: #cbd5e1; border-color: #e2e8f0; cursor: not-allowed; }
.btn-ghost { background: transparent; color: #94a3b8; border: 1px solid #e2e8f0; flex: 0 0 auto; padding: 11px 16px; }
.btn-ghost:hover { background: #f8fafc; color: #64748b; }
.btn-ghost:disabled { color: #cbd5e1; border-color: #e2e8f0; cursor: not-allowed; }

/* ── Mobile ── */
@media (max-width: 640px) {
    .grade-nav { gap: 0; }
    .gtab { padding: 5px 8px; font-size: 12px; }
    .stat-pills { display: none; }
    .hero-deco { display: none; }
    .card-grid { grid-template-columns: 1fr 1fr; gap: 8px; }
    .card-body { padding: 12px; }
    .card-school { font-size: 14px; }
    .action-btn { font-size: 11px; padding: 8px 2px; }
    .filter-inner { flex-wrap: wrap; }
    .fb-sel-group { flex-wrap: wrap; }
}
